def analyze_scores(scores):
    if not scores:
        return {'average_score': 0, 'highest_score': 0, 'lowest_score': 0, 'passed': 0, 'failed': 0}
    total = sum(scores)
    average = total / len(scores)
    highest = max(scores)
    lowest = min(scores)
    passed = sum(1 for s in scores if s >= 60)
    failed = sum(1 for s in scores if s < 60)
    return {'average_score': average, 'highest_score': highest, 'lowest_score': lowest, 'passed': passed, 'failed': failed}
